import React from "react";
import { Box, Speak, SubBox, TitleText } from "../Styles/Styled";
import { MedStudent, Developer, Engineer, Blog, Dance } from "../Styles/Icons";
import styled from "styled-components";
import SvgCard from "./Card";
import ScrollAnimation from "react-animate-on-scroll";
import { ArrowDown, ArrowUp } from "../Styles/Icons";
import { HashLink as Link } from "react-router-hash-link";
import Theme from "../Styles/Theme";

const BoxTitle = styled.div`
  margin-top: ${Theme.small};
`;
const BoxContent = styled.div`
  margin-top: ${Theme.medium};
  justify-content: space-around;
  display: flex;
  width: 80%;
`;

const BoxCaption = styled.div`
  margin-top: ${Theme.medium};
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
`;

export default () => {
  return (
    <Box id="intro" width="100%" bgColor={"#fef6ea"}>
      <SubBox
        style={{
          minHeight: "48vw",
          height: "100%",
          paddingTop: Theme.large,
          paddingBottom: Theme.large
        }}
        basis={80}
      >
        <BoxTitle>
          <ScrollAnimation animateIn="bounceInRight" animateOnce={true}>
            <TitleText size={Theme.medSmall}>자기소개</TitleText>
          </ScrollAnimation>
        </BoxTitle>

        <BoxContent>
          <SvgCard
            delay={0}
            scrollAnimation={"bounce"}
            text="의과대학생"
            color="#4287f5"
            fontColor="black"
            svgElement={<MedStudent size={Theme.large.slice(0, -2)} />}
          />
          <SvgCard
            delay={400}
            scrollAnimation={"bounce"}
            text="아마추어 개발자"
            color="#ab2b25"
            fontColor="black"
            svgElement={<Developer size={Theme.large.slice(0, -2)} />}
          />

          <SvgCard
            delay={800}
            scrollAnimation={"bounce"}
            text="아마추어 엔지니어"
            color="#209661"
            fontColor="black"
            svgElement={<Engineer size={Theme.large.slice(0, -2)} />}
          />
          <SvgCard
            delay={1200}
            scrollAnimation={"bounce"}
            text="글쓰기"
            color="#ab6f24"
            fontColor="black"
            svgElement={<Blog size={Theme.large.slice(0, -2)} />}
          />
          <SvgCard
            delay={1600}
            scrollAnimation={"bounce"}
            text="기타 여가활동"
            color="#6f24ab"
            fontColor="black"
            svgElement={<Dance size={Theme.large.slice(0, -2)} />}
          />
        </BoxContent>

        <BoxCaption>
          <Speak 
            fontSize={Theme.xsmall}
          >
            간략하게 표현하면 이런 사람입니다.
          </Speak>
          <Speak fontSize={Theme.xsmall}>
            클릭하면 더 많은 내용을 보실 수 있어요.
          </Speak>
        </BoxCaption>
      </SubBox>
      <ScrollAnimation
        style={{ position: "absolute", bottom: "0" }}
        animateIn={"fadeIn"}
        duration={1}
        animateOnce={true}
      >
        <Link style={{ marginTop: Theme.small }} smooth to="/#medStudent">
          <SvgCard
            display="inline"
            scrollAnimation="pulse infinite"
            cardSize={Theme.medSmall}
            color="black"
            text={""}
            fontColor="black"
            padding={false}
            initiallyVisible={true}
            svgElement={<ArrowDown size={Theme.medSmall.slice(0, -2)} />}
          />
        </Link>
      </ScrollAnimation>
      <ScrollAnimation
        style={{ position: "absolute", top: "0" }}
        animateIn={"fadeIn"}
        duration={1}
        animateOnce={true}
      >
        <Link style={{ marginTop: Theme.small }} smooth to="/#title">
          <SvgCard
            display="inline"
            scrollAnimation="pulse infinite"
            cardSize={Theme.medSmall}
            color="black"
            text={""}
            fontColor="black"
            padding={false}
            initiallyVisible={true}
            svgElement={<ArrowUp size={Theme.medSmall.slice(0, -2)} />}
          />
        </Link>
      </ScrollAnimation>
    </Box>
  );
};
